    this.verifyRoundTrip("[a](<b(c>)\n");
    this.verifyRoundTrip("[a](<b\\>c>)\n");
    this.verifyRoundTrip("[a](<b\\\\\\>c>)\n");
    this.verifyRoundTrip("[a](/uri \"foo \\\" bar\")\n");
    this.verifyRoundTrip("[link](/uri \"tes\\\\\")\n");
